See https://github.com/pthom/pybind_numpy_error

This is a minimal reproduction of the error (10 lines of code + CMakeLists)

## strace under linux : 

See https://raw.githubusercontent.com/pthom/pybind_numpy_error/master/strace.txt

```
class MySubFactory(factory.DjangoModelFactory):
    class Meta:
        model = MySubModel

    @classmethod
    def create(cls, **kwargs):
        print("HELLO")
        return super().create(**kwargs)

class MyFactory(factory.DjangoModelFactory):
    class Meta:
        model = MyModel

    rel = factory.SubFactory(MySubFactory)

# factory_boy==2.8.1 and lower

>> MyFactory.create()
"HELLO"

# factory_boy==2.9.0 and higher

>> MyFactory.create()
